1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
8	const FIRST_INSURANCE_RATE = 0.1;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	
13	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	const INSURANCE_VALUES: Record<string, number> = {
21	  sword: 1000,
22	  amulet: 600,
23	  staff: 800,
24	  potion: 400,
25	};
26	
27	const COMPONENT_INSURANCE_VALUE = 250;
28	const DEDUCTIBLE = 100;
29	const CAP_MULTIPLIER = 2;
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
34	
35	const isKnownItemType = (item: any): boolean =>
36	  item.type in MAIN_ITEM_PREMIUMS || COMPONENT_TYPES.has(item.type);
37	
38	const mainItemBasePremium = (item: any): number =>
39	  MAIN_ITEM_PREMIUMS[item.type] ?? 0;
40	
41	const componentGroupPremium = (count: number): number =>
42	  count === COMPONENT_BLOCK_SIZE
43	    ? COMPONENT_BLOCK_PREMIUM
44	    : count * COMPONENT_PREMIUM;
45	
46	const calculateMainItemBaseTotal = (mainItems: any[]): number =>
47	  mainItems.reduce(
48	    (sum, item) => sum + mainItemBasePremium(item),
49	    0,
50	  );
51	
52	const calculateComponentTotal = (components: any[]): number => {
53	  const componentCounts: Record<string, number> = {};
54	  for (const item of components) {
55	    componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
56	  }
57	  return Object.values(componentCounts).reduce(
58	    (sum, count) => sum + componentGroupPremium(count),
59	    0,
60	  );
61	};
62	
63	const calculateItemLevelSurcharges = (mainItems: any[]): number =>
64	  mainItems.reduce((sum, item) => {
65	    const base = mainItemBasePremium(item);
66	    const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
67	    const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
68	    return sum + cursedSurcharge + enchantmentSurcharge;
69	  }, 0);
70	
71	const validateItems = (items: any[]): void => {
72	  for (const item of items) {
73	    if (!isKnownItemType(item)) {
74	      throw new Error(`Unknown item type: ${item.type}`);
75	    }
76	  }
77	};
78	
79	const calculateInsuranceSum = (items: any[]): number =>
80	  items.reduce(
81	    (sum: number, item: any) =>
82	      sum + (isComponent(item) ? COMPONENT_INSURANCE_VALUE : (INSURANCE_VALUES[item.type] ?? 0)),
83	    0,
84	  );
85	
86	const calculatePremium = (items: any[], customer: any, quoteCount: number): number => {
87	  const mainItems = items.filter((item: any) => !isComponent(item));
88	  const components = items.filter(isComponent);
89	  const basePremiumSum = calculateMainItemBaseTotal(mainItems) + calculateComponentTotal(components);
90	  const itemSurcharges = calculateItemLevelSurcharges(mainItems);
91	  const firstInsurance = basePremiumSum * FIRST_INSURANCE_RATE;
92	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremiumSum * LOYALTY_DISCOUNT_RATE : 0;
93	  const followUpDiscount = quoteCount > 0 ? basePremiumSum * FOLLOW_UP_DISCOUNT_RATE : 0;
94	  return Math.ceil(basePremiumSum + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
95	};
96	
97	const CLAIM_ENCHANTMENT_THRESHOLD = 8;
98	const CLAIM_ENCHANTMENT_RATE = 0.5;
99	
100	const calculateReimbursement = (damage: any, policyItem: any): number => {
101	  const hasHighEnchantment = policyItem && policyItem.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD;
102	  const reimbursement = hasHighEnchantment
103	    ? damage.amount * CLAIM_ENCHANTMENT_RATE
104	    : damage.amount;
105	  return Math.max(0, reimbursement - DEDUCTIBLE);
106	};
107	
108	const calculateClaimPayout = (damages: any[], policyItems: any[]): number =>
109	  damages.reduce((total: number, damage: any) => {
110	    const policyItem = policyItems.find((i: any) => i.type === damage.itemType);
111	    return total + calculateReimbursement(damage, policyItem);
112	  }, 0);
113	
114	export const processScenario = (scenario: any): any => {
115	  const results: any[] = [];
116	  const policies: Record<number, { items: any[]; remainingCap: number }> = {};
117	  let quoteCount = 0;
118	  for (let i = 0; i < scenario.steps.length; i++) {
119	    const step = scenario.steps[i];
120	    if (step.op === "quote") {
121	      validateItems(step.items);
122	      const premium = calculatePremium(step.items, scenario.customer, quoteCount);
123	      const insuranceSum = calculateInsuranceSum(step.items);
124	      policies[i] = { items: step.items, remainingCap: insuranceSum * CAP_MULTIPLIER };
125	      results.push({ premium });
126	      quoteCount++;
127	    } else if (step.op === "claim") {
128	      const policy = policies[step.policy];
129	      const policyItemCounts: Record<string, number> = {};
130	      for (const item of policy.items) {
131	        policyItemCounts[item.type] = (policyItemCounts[item.type] ?? 0) + 1;
132	      }
133	      const damageItemCounts: Record<string, number> = {};
134	      for (const damage of step.incident.damages) {
135	        if (damage.amount < 0) {
136	          throw new Error(`Negative damage amount: ${damage.amount}`);
137	        }
138	        damageItemCounts[damage.itemType] = (damageItemCounts[damage.itemType] ?? 0) + 1;
139	      }
140	      for (const [type, count] of Object.entries(damageItemCounts)) {
141	        if ((policyItemCounts[type] ?? 0) < count) {
142	          throw new Error(`Too many damage entries for item type ${type}`);
143	        }
144	      }
145	      const rawPayout = calculateClaimPayout(step.incident.damages, policy.items);
146	      const totalPayout = Math.min(rawPayout, policy.remainingCap);
147	      policy.remainingCap -= totalPayout;
148	      results.push({ payout: totalPayout, remainingCap: policy.remainingCap });
149	    }
150	  }
151	  return { results };
152	};
