151	      const rawPayout = calculateClaimPayout(step.incident.damages, policy.items);
152	      const totalPayout = Math.min(rawPayout, policy.remainingCap);
153	      policy.remainingCap -= totalPayout;
154	      results.push({ payout: totalPayout, remainingCap: policy.remainingCap });
155	    }
156	  }
157	  return { results };
158	};
